contracts/KimuntuXCommissionSystem.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

contract KimuXCommissionSystem is Ownable, ReentrancyGuard, Pausable {
    struct Commission {
        address affiliate;
        uint256 amount;
        uint256 timestamp;
        string transactionId;
        CommissionStatus status;
    }

    enum CommissionStatus {
        Pending,
        Approved,
        Paid,
        Disputed
    }

    mapping(address => uint256) public balances;
    mapping(address => Commission[]) public commissions;
    mapping(string => bool) public processedTransactions;
    mapping(address => bool) public authorizedMerchants;
    mapping(address => bool) public registeredAffiliates;

    uint256 public totalCommissionsPaid;
    uint256 public platformFeeRate = 300;
    uint256 public minimumPayout = 0.01 ether;

    event AffiliateRegistered(address indexed affiliate, uint256 timestamp);
    event CommissionRecorded(address indexed affiliate, uint256 amount, string transactionId);
    event CommissionApproved(address indexed affiliate, uint256 amount);
    event CommissionPaid(address indexed affiliate, uint256 amount);
    event CommissionDisputed(address indexed affiliate, string transactionId);
    event MerchantAuthorized(address indexed merchant, bool status);

    constructor() Ownable(msg.sender) {
        authorizedMerchants[msg.sender] = true;
    }

    modifier onlyMerchant() {
        require(authorizedMerchants[msg.sender] || msg.sender == owner(), "Not authorized");
        _;
    }

    modifier onlyAffiliate() {
        require(registeredAffiliates[msg.sender], "Not registered affiliate");
        _;
    }

    function registerAffiliate(address _affiliate) external onlyOwner {
        require(_affiliate != address(0), "Invalid address");
        require(!registeredAffiliates[_affiliate], "Already registered");
        registeredAffiliates[_affiliate] = true;
        emit AffiliateRegistered(_affiliate, block.timestamp);
    }

    function registerSelf() external {
        require(!registeredAffiliates[msg.sender], "Already registered");
        registeredAffiliates[msg.sender] = true;
        emit AffiliateRegistered(msg.sender, block.timestamp);
    }

    function recordCommission(
        address _affiliate,
        uint256 _saleAmount,
        uint256 _commissionRate,
        string memory _transactionId
    ) external payable onlyMerchant whenNotPaused {
        require(registeredAffiliates[_affiliate], "Affiliate not registered");
        require(_saleAmount > 0, "Invalid sale amount");
        require(!processedTransactions[_transactionId], "Transaction already processed");

        uint256 commissionAmount = (_saleAmount * _commissionRate) / 10000;
        uint256 platformFee = (commissionAmount * platformFeeRate) / 10000;
        uint256 netCommission = commissionAmount - platformFee;

        require(msg.value >= commissionAmount, "Insufficient payment");

        Commission memory newCommission = Commission({
            affiliate: _affiliate,
            amount: netCommission,
            timestamp: block.timestamp,
            transactionId: _transactionId,
            status: CommissionStatus.Pending
        });

        commissions[_affiliate].push(newCommission);
        processedTransactions[_transactionId] = true;

        emit CommissionRecorded(_affiliate, netCommission, _transactionId);

        if (msg.value > commissionAmount) {
            payable(msg.sender).transfer(msg.value - commissionAmount);
        }
    }

    function approveCommission(address _affiliate, uint256 _commissionIndex) external onlyMerchant {
        require(_commissionIndex < commissions[_affiliate].length, "Invalid index");
        Commission storage comm = commissions[_affiliate][_commissionIndex];
        require(comm.status == CommissionStatus.Pending, "Not pending");

        comm.status = CommissionStatus.Approved;
        balances[_affiliate] += comm.amount;
        emit CommissionApproved(_affiliate, comm.amount);
    }

    function autoApprove(address _affiliate, string memory _transactionId) external onlyMerchant {
        Commission[] storage affiliateComms = commissions[_affiliate];
        for (uint256 i = 0; i < affiliateComms.length; i++) {
            if (
                keccak256(bytes(affiliateComms[i].transactionId)) == keccak256(bytes(_transactionId)) &&
                affiliateComms[i].status == CommissionStatus.Pending
            ) {
                affiliateComms[i].status = CommissionStatus.Approved;
                balances[_affiliate] += affiliateComms[i].amount;
                emit CommissionApproved(_affiliate, affiliateComms[i].amount);
                return;
            }
        }
        revert("Commission not found");
    }

    function withdraw() external onlyAffiliate nonReentrant whenNotPaused {
        uint256 amount = balances[msg.sender];
        require(amount >= minimumPayout, "Below minimum payout");
        require(address(this).balance >= amount, "Insufficient contract balance");

        balances[msg.sender] = 0;
        totalCommissionsPaid += amount;

        (bool success, ) = payable(msg.sender).call{value: amount}("");
        require(success, "Transfer failed");
        emit CommissionPaid(msg.sender, amount);
    }

    function withdrawAmount(uint256 _amount) external onlyAffiliate nonReentrant whenNotPaused {
        require(_amount > 0, "Invalid amount");
        require(_amount >= minimumPayout, "Below minimum payout");
        require(balances[msg.sender] >= _amount, "Insufficient balance");
        require(address(this).balance >= _amount, "Insufficient contract balance");

        balances[msg.sender] -= _amount;
        totalCommissionsPaid += _amount;

        (bool success, ) = payable(msg.sender).call{value: _amount}("");
        require(success, "Transfer failed");
        emit CommissionPaid(msg.sender, _amount);
    }

    function authorizeMerchant(address _merchant, bool _status) external onlyOwner {
        authorizedMerchants[_merchant] = _status;
        emit MerchantAuthorized(_merchant, _status);
    }

    function setPlatformFeeRate(uint256 _newRate) external onlyOwner {
        require(_newRate <= 1000, "Fee too high (max 10%)");
        platformFeeRate = _newRate;
    }

    function setMinimumPayout(uint256 _newMinimum) external onlyOwner {
        minimumPayout = _newMinimum;
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    function withdrawPlatformFees() external onlyOwner nonReentrant {
        uint256 contractBalance = address(this).balance;
        uint256 totalPending = 0;
        require(contractBalance > totalPending, "No fees to withdraw");
        uint256 fees = contractBalance - totalPending;
        (bool success, ) = payable(owner()).call{value: fees}("");
        require(success, "Transfer failed");
    }

    function getBalance(address _affiliate) external view returns (uint256) {
        return balances[_affiliate];
    }

    function getCommissionCount(address _affiliate) external view returns (uint256) {
        return commissions[_affiliate].length;
    }

    function getCommission(address _affiliate, uint256 _index) external view returns (
        uint256 amount,
        uint256 timestamp,
        string memory transactionId,
        CommissionStatus status
    ) {
        require(_index < commissions[_affiliate].length, "Invalid index");
        Commission memory comm = commissions[_affiliate][_index];
        return (comm.amount, comm.timestamp, comm.transactionId, comm.status);
    }

    function getAllCommissions(address _affiliate) external view returns (Commission[] memory) {
        return commissions[_affiliate];
    }

    function getContractStats() external view returns (
        uint256 contractBalance,
        uint256 totalPaid,
        uint256 feeRate,
        uint256 minPayout
    ) {
        return (address(this).balance, totalCommissionsPaid, platformFeeRate, minimumPayout);
    }

    function isAffiliate(address _address) external view returns (bool) {
        return registeredAffiliates[_address];
    }

    function isMerchant(address _address) external view returns (bool) {
        return authorizedMerchants[_address];
    }

    receive() external payable {}
}

contracts/KimuntuXWallet.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract KimuXWallet is Ownable, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    struct Wallet {
        address owner;
        uint256 ethBalance;
        mapping(address => uint256) tokenBalances;
        bool exists;
        uint256 createdAt;
        uint256 totalDeposits;
        uint256 totalWithdrawals;
    }

    struct SupportedToken {
        address tokenAddress;
        string symbol;
        bool isActive;
    }

    mapping(address => Wallet) private wallets;
    mapping(address => bool) public walletExists;
    mapping(address => SupportedToken) public supportedTokens;
    mapping(address => bool) public authorizedPlatforms;

    address[] public allWalletAddresses;
    address[] public tokenAddressList;

    uint256 public totalWallets;
    uint256 public minimumWithdrawalAmount;

    event WalletCreated(address indexed owner, uint256 timestamp);
    event ETHDeposit(address indexed wallet, uint256 amount, uint256 timestamp);
    event TokenDeposit(address indexed wallet, address indexed token, uint256 amount, string symbol, uint256 timestamp);
    event ETHWithdrawal(address indexed wallet, uint256 amount, uint256 timestamp);
    event TokenWithdrawal(address indexed wallet, address indexed token, uint256 amount, string symbol, uint256 timestamp);
    event Transfer(address indexed from, address indexed to, uint256 amount, address token, uint256 timestamp);
    event TokenAdded(address indexed token, string symbol);
    event TokenRemoved(address indexed token, string symbol);
    event PlatformAuthorized(address indexed platform);
    event PlatformRevoked(address indexed platform);
    event MinimumWithdrawalUpdated(uint256 newMinimum);

    constructor(uint256 _minimumWithdrawalAmount) Ownable(msg.sender) {
        minimumWithdrawalAmount = _minimumWithdrawalAmount;
        authorizedPlatforms[msg.sender] = true;
    }

    modifier walletMustExist(address _owner) {
        require(walletExists[_owner], "Wallet does not exist");
        _;
    }

    modifier onlyAuthorizedPlatform() {
        require(authorizedPlatforms[msg.sender], "Not authorized platform");
        _;
    }

    function createWallet() external whenNotPaused {
        require(!walletExists[msg.sender], "Wallet already exists");

        Wallet storage newWallet = wallets[msg.sender];
        newWallet.owner = msg.sender;
        newWallet.exists = true;
        newWallet.createdAt = block.timestamp;

        walletExists[msg.sender] = true;
        allWalletAddresses.push(msg.sender);
        totalWallets++;

        emit WalletCreated(msg.sender, block.timestamp);
    }

    function createWalletFor(address _user) external onlyAuthorizedPlatform whenNotPaused {
        require(_user != address(0), "Invalid address");
        require(!walletExists[_user], "Wallet already exists");

        Wallet storage newWallet = wallets[_user];
        newWallet.owner = _user;
        newWallet.exists = true;
        newWallet.createdAt = block.timestamp;

        walletExists[_user] = true;
        allWalletAddresses.push(_user);
        totalWallets++;

        emit WalletCreated(_user, block.timestamp);
    }

    function depositETH() external payable walletMustExist(msg.sender) whenNotPaused {
        require(msg.value > 0, "Deposit amount must be greater than 0");
        Wallet storage wallet = wallets[msg.sender];
        wallet.ethBalance += msg.value;
        wallet.totalDeposits += msg.value;
        emit ETHDeposit(msg.sender, msg.value, block.timestamp);
    }

    function creditETH(address _user, uint256 _amount) external payable onlyAuthorizedPlatform walletMustExist(_user) whenNotPaused {
        require(_amount > 0, "Amount must be greater than 0");
        require(msg.value == _amount, "Sent value must match amount");
        Wallet storage wallet = wallets[_user];
        wallet.ethBalance += _amount;
        wallet.totalDeposits += _amount;
        emit ETHDeposit(_user, _amount, block.timestamp);
    }

    function depositToken(address _token, uint256 _amount) external walletMustExist(msg.sender) whenNotPaused {
        require(_amount > 0, "Deposit amount must be greater than 0");
        require(supportedTokens[_token].isActive, "Token not supported");
        Wallet storage wallet = wallets[msg.sender];
        IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);
        wallet.tokenBalances[_token] += _amount;
        emit TokenDeposit(msg.sender, _token, _amount, supportedTokens[_token].symbol, block.timestamp);
    }

    function creditToken(address _user, address _token, uint256 _amount) external onlyAuthorizedPlatform walletMustExist(_user) whenNotPaused {
        require(_amount > 0, "Amount must be greater than 0");
        require(supportedTokens[_token].isActive, "Token not supported");
        Wallet storage wallet = wallets[_user];
        IERC20(_token).safeTransferFrom(msg.sender, address(this), _amount);
        wallet.tokenBalances[_token] += _amount;
        emit TokenDeposit(_user, _token, _amount, supportedTokens[_token].symbol, block.timestamp);
    }

    function withdrawETH(uint256 _amount) external nonReentrant walletMustExist(msg.sender) whenNotPaused {
        require(_amount > 0, "Withdrawal amount must be greater than 0");
        require(_amount >= minimumWithdrawalAmount, "Below minimum withdrawal amount");
        Wallet storage wallet = wallets[msg.sender];
        require(wallet.ethBalance >= _amount, "Insufficient balance");
        wallet.ethBalance -= _amount;
        wallet.totalWithdrawals += _amount;
        (bool success, ) = msg.sender.call{value: _amount}("");
        require(success, "ETH transfer failed");
        emit ETHWithdrawal(msg.sender, _amount, block.timestamp);
    }

    function withdrawAllETH() external nonReentrant walletMustExist(msg.sender) whenNotPaused {
        Wallet storage wallet = wallets[msg.sender];
        uint256 balance = wallet.ethBalance;
        require(balance > 0, "No ETH balance");
        require(balance >= minimumWithdrawalAmount, "Below minimum withdrawal amount");
        wallet.ethBalance = 0;
        wallet.totalWithdrawals += balance;
        (bool success, ) = msg.sender.call{value: balance}("");
        require(success, "ETH transfer failed");
        emit ETHWithdrawal(msg.sender, balance, block.timestamp);
    }

    function withdrawToken(address _token, uint256 _amount) external nonReentrant walletMustExist(msg.sender) whenNotPaused {
        require(_amount > 0, "Withdrawal amount must be greater than 0");
        require(supportedTokens[_token].isActive, "Token not supported");
        Wallet storage wallet = wallets[msg.sender];
        require(wallet.tokenBalances[_token] >= _amount, "Insufficient token balance");
        wallet.tokenBalances[_token] -= _amount;
        IERC20(_token).safeTransfer(msg.sender, _amount);
        emit TokenWithdrawal(msg.sender, _token, _amount, supportedTokens[_token].symbol, block.timestamp);
    }

    function transferETH(address _recipient, uint256 _amount) external walletMustExist(msg.sender) walletMustExist(_recipient) whenNotPaused {
        require(_amount > 0, "Transfer amount must be greater than 0");
        require(_recipient != msg.sender, "Cannot transfer to self");
        Wallet storage senderWallet = wallets[msg.sender];
        Wallet storage recipientWallet = wallets[_recipient];
        require(senderWallet.ethBalance >= _amount, "Insufficient balance");
        senderWallet.ethBalance -= _amount;
        recipientWallet.ethBalance += _amount;
        emit Transfer(msg.sender, _recipient, _amount, address(0), block.timestamp);
    }

    function transferToken(address _recipient, address _token, uint256 _amount) external walletMustExist(msg.sender) walletMustExist(_recipient) whenNotPaused {
        require(_amount > 0, "Transfer amount must be greater than 0");
        require(_recipient != msg.sender, "Cannot transfer to self");
        require(supportedTokens[_token].isActive, "Token not supported");
        Wallet storage senderWallet = wallets[msg.sender];
        Wallet storage recipientWallet = wallets[_recipient];
        require(senderWallet.tokenBalances[_token] >= _amount, "Insufficient token balance");
        senderWallet.tokenBalances[_token] -= _amount;
        recipientWallet.tokenBalances[_token] += _amount;
        emit Transfer(msg.sender, _recipient, _amount, _token, block.timestamp);
    }

    function getETHBalance(address _owner) external view walletMustExist(_owner) returns (uint256) {
        return wallets[_owner].ethBalance;
    }

    function getTokenBalance(address _owner, address _token) external view walletMustExist(_owner) returns (uint256) {
        return wallets[_owner].tokenBalances[_token];
    }

    function getAllBalances(address _owner) external view walletMustExist(_owner) returns (
        uint256 ethBalance,
        uint256[] memory tokenBalances,
        address[] memory tokenAddresses
    ) {
        Wallet storage wallet = wallets[_owner];
        ethBalance = wallet.ethBalance;
        uint256 tokenCount = tokenAddressList.length;
        tokenBalances = new uint256[](tokenCount);
        tokenAddresses = new address[](tokenCount);
        for (uint256 i = 0; i < tokenCount; i++) {
            address tokenAddr = tokenAddressList[i];
            tokenAddresses[i] = tokenAddr;
            tokenBalances[i] = wallet.tokenBalances[tokenAddr];
        }
        return (ethBalance, tokenBalances, tokenAddresses);
    }

    function getWalletDetails(address _owner) external view walletMustExist(_owner) returns (
        address owner,
        uint256 ethBalance,
        uint256 createdAt,
        uint256 totalDeposits,
        uint256 totalWithdrawals
    ) {
        Wallet storage wallet = wallets[_owner];
        return (wallet.owner, wallet.ethBalance, wallet.createdAt, wallet.totalDeposits, wallet.totalWithdrawals);
    }

    function hasWallet(address _owner) external view returns (bool) {
        return walletExists[_owner];
    }

    function getTotalWallets() external view returns (uint256) {
        return totalWallets;
    }

    function getAllWallets() external view returns (address[] memory) {
        return allWalletAddresses;
    }

    function getSupportedTokens() external view returns (address[] memory) {
        return tokenAddressList;
    }

    function addSupportedToken(address _token, string memory _symbol) external onlyOwner {
        require(_token != address(0), "Invalid token address");
        require(!supportedTokens[_token].isActive, "Token already supported");
        supportedTokens[_token] = SupportedToken({ tokenAddress: _token, symbol: _symbol, isActive: true });
        tokenAddressList.push(_token);
        emit TokenAdded(_token, _symbol);
    }

    function removeSupportedToken(address _token) external onlyOwner {
        require(supportedTokens[_token].isActive, "Token not supported");
        string memory symbol = supportedTokens[_token].symbol;
        supportedTokens[_token].isActive = false;
        emit TokenRemoved(_token, symbol);
    }

    function authorizePlatform(address _platform) external onlyOwner {
        require(_platform != address(0), "Invalid platform address");
        authorizedPlatforms[_platform] = true;
        emit PlatformAuthorized(_platform);
    }

    function revokePlatform(address _platform) external onlyOwner {
        authorizedPlatforms[_platform] = false;
        emit PlatformRevoked(_platform);
    }

    function updateMinimumWithdrawal(uint256 _newMinimum) external onlyOwner {
        minimumWithdrawalAmount = _newMinimum;
        emit MinimumWithdrawalUpdated(_newMinimum);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    function emergencyWithdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        require(balance > 0, "No balance to withdraw");
        (bool success, ) = owner().call{value: balance}("");
        require(success, "Transfer failed");
    }

    function emergencyWithdrawToken(address _token) external onlyOwner {
        uint256 balance = IERC20(_token).balanceOf(address(this));
        require(balance > 0, "No token balance");
        IERC20(_token).safeTransfer(owner(), balance);
    }

    receive() external payable {}

    fallback() external payable {
        revert("Function does not exist");
    }
}

